TriggerOraclev10g.body:
DECLARE envbq_status number; valor_envbq_update number; vro_error tkr_errores%ROWTYPE; BEGIN -- En el caso de INSERT IF INSERTING THEN
SELECT (SELECT ENVIO_BQ FROM TKRBQ_SOLICITUD_DOCTOR WHERE ID = :NEW.ID AND ENVIO_BQ != 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NOT NULL THEN DELETE TKRBQ_SOLICITUD_DOCTOR WHERE ID = :NEW.ID AND ENVIO_BQ != 1; END IF;
INSERT INTO TKRBQ_SOLICITUD_DOCTOR ( ENVIO_BQ, ID, ID_USUARIO, FECHA, TIEMPO_EXPERIENCIA, TIEMPO_EXP_SALUD_VIRTUAL, FECHA_CREACION, ID_PAIS ) VALUES ( 0, -- ENVIO_BQ por defecto :NEW.ID, :NEW.ID_USUARIO, :NEW.FECHA, :NEW.TIEMPO_EXPERIENCIA, :NEW.TIEMPO_EXP_SALUD_VIRTUAL, :NEW.FECHA_CREACION, :NEW.ID_PAIS ); END IF;
-- En el caso de UPDATE IF UPDATING THEN SELECT (SELECT ENVIO_BQ FROM TKRBQ_SOLICITUD_DOCTOR WHERE ID = :NEW.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NULL THEN
INSERT INTO TKRBQ_SOLICITUD_DOCTOR ( ENVIO_BQ, ID, ID_USUARIO, FECHA, TIEMPO_EXPERIENCIA, TIEMPO_EXP_SALUD_VIRTUAL, FECHA_CREACION, ID_PAIS ) VALUES ( 2, -- ENVIO_BQ por defecto :NEW.ID, :NEW.ID_USUARIO, :NEW.FECHA, :NEW.TIEMPO_EXPERIENCIA, :NEW.TIEMPO_EXP_SALUD_VIRTUAL, :NEW.FECHA_CREACION, :NEW.ID_PAIS );
ELSE IF envbq_status = 0 THEN valor_envbq_update := 0; ELSE valor_envbq_update := 2; END IF;
UPDATE TKRBQ_SOLICITUD_DOCTOR SET ENVIO_BQ = valor_envbq_update, ID = :NEW.ID, ID_USUARIO = :NEW.ID_USUARIO, FECHA = :NEW.FECHA, TIEMPO_EXPERIENCIA = :NEW.TIEMPO_EXPERIENCIA, TIEMPO_EXP_SALUD_VIRTUAL = :NEW.TIEMPO_EXP_SALUD_VIRTUAL, FECHA_CREACION = :NEW.FECHA_CREACION, ID_PAIS = :NEW.ID_PAIS WHERE ID = :OLD.ID AND ENVIO_BQ != 1; END IF; END IF;
-- Caso DELETE IF DELETING THEN
SELECT (SELECT ENVIO_BQ FROM TKRBQ_SOLICITUD_DOCTOR WHERE ID = :OLD.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NOT NULL THEN DELETE TKRBQ_SOLICITUD_DOCTOR WHERE ID = :OLD.ID AND ENVIO_BQ != 1; END IF;
INSERT INTO TKRBQ_SOLICITUD_DOCTOR ( ENVIO_BQ, ID, ID_USUARIO, FECHA, TIEMPO_EXPERIENCIA, TIEMPO_EXP_SALUD_VIRTUAL, FECHA_CREACION, ID_PAIS ) VALUES ( -1, -- ENVIO_BQ para DELETE :OLD.ID, :OLD.ID_USUARIO, :OLD.FECHA, :OLD.TIEMPO_EXPERIENCIA, :OLD.TIEMPO_EXP_SALUD_VIRTUAL, :OLD.FECHA_CREACION, :OLD.ID_PAIS ); END IF;
EXCEPTION WHEN OTHERS THEN vro_error.nombre_programa := 'TKR_SOLICITUD_DOCTOR'; vro_error.nombre_metodo := 'TRIGGER_SYNC_BQ'; vro_error.parametros := 'id de consultas: '||:old.id; uti_ge_excepciones_pkg.p_grabar_log (vro_error);
END;
